import { useCallback, useEffect, useMemo, useRef } from 'react';
import { useEditor } from '@/app/EditorProvider';
import { useProject } from '@/app/ProjectProvider';
import { MAX_ZOOM, MIN_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
import { fitViewportToSheet } from '@/sheets/layout';
import { hitTestViewport, hitTestViewportHandle, hitTestViewportRotationHandle } from '@/sheets/hitTest';
import { buildSheetScene } from '@/sheets/layout';
import styles from './SvgCanvas.module.css';
import SheetRenderer from './SheetRenderer';

function screenToSheet(screenX, screenY, viewport, svgRect) {
  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
  return { x, y };
}

export default function SheetCanvas() {
  const svgRef = useRef(null);
  const dragState = useRef(null);
  const activePointerId = useRef(null);
  const isPanning = useRef(false);
  const lastPanPos = useRef({ x: 0, y: 0 });

  const { project, dispatch } = useProject();
  const {
    activeSheetId,
    selectedId,
    selectedType,
    viewport,
    dispatch: editorDispatch,
  } = useEditor();

  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);

  const getSheetPos = useCallback((event) => {
    const rect = svgRef.current.getBoundingClientRect();
    return screenToSheet(event.clientX, event.clientY, viewport, rect);
  }, [viewport]);

  const updateViewport = useCallback((viewportId, updates) => {
    if (!sheet) return;
    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
    if (!current) return;
    const sceneViewport = scene?.viewports.find((entry) => entry.id === viewportId) || null;
    const isManualEdit = ['x', 'y', 'width', 'height', 'rotation'].some((key) => key in updates);
    const baseViewport = sceneViewport
      ? {
          ...current,
          x: sceneViewport.x,
          y: sceneViewport.y,
          width: sceneViewport.width,
          height: sceneViewport.height,
          rotation: sceneViewport.rotation,
        }
      : current;
    const nextViewport = fitViewportToSheet({
      ...baseViewport,
      ...updates,
      lockAutoLayout: 'lockAutoLayout' in updates
        ? updates.lockAutoLayout
        : (isManualEdit ? true : baseViewport.lockAutoLayout),
    }, sheet);
    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
  }, [dispatch, scene?.viewports, sheet]);

  const capturePointer = useCallback((pointerId) => {
    if (!svgRef.current) return;
    activePointerId.current = pointerId;
    try {
      svgRef.current.setPointerCapture(pointerId);
    } catch {
      activePointerId.current = pointerId;
    }
  }, []);

  const releasePointer = useCallback((pointerId = activePointerId.current) => {
    if (!svgRef.current || pointerId == null) {
      activePointerId.current = null;
      return;
    }
    try {
      if (svgRef.current.hasPointerCapture?.(pointerId)) {
        svgRef.current.releasePointerCapture(pointerId);
      }
    } catch {
      // Ignore browsers that reject release calls after capture is already gone.
    }
    activePointerId.current = null;
  }, []);

  const handlePointerDown = useCallback((event) => {
    if (activePointerId.current !== null && activePointerId.current !== event.pointerId) return;

    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
      capturePointer(event.pointerId);
      isPanning.current = true;
      lastPanPos.current = { x: event.clientX, y: event.clientY };
      event.preventDefault();
      return;
    }

    if (event.button !== 0) return;

    if (!sheet || !scene) return;

    const point = getSheetPos(event);

    if (selectedType === 'sheetViewport' && selectedId) {
      const selectedVp = scene.viewports.find((entry) => entry.id === selectedId);
      if (selectedVp && hitTestViewportRotationHandle(point, selectedVp, 6 / viewport.zoom)) {
        const cx = selectedVp.x + selectedVp.width / 2;
        const cy = selectedVp.y + selectedVp.height / 2;
        dragState.current = {
          mode: 'rotate',
          viewportId: selectedId,
          center: { x: cx, y: cy },
          initialRotation: selectedVp.rotation || 0,
          startAngle: Math.atan2(point.y - cy, point.x - cx) * (180 / Math.PI),
        };
        capturePointer(event.pointerId);
        event.preventDefault();
        return;
      }
    }

    const handleViewportCandidates = selectedType === 'sheetViewport' && selectedId
      ? [
          ...scene.viewports.filter((entry) => entry.id === selectedId),
          ...scene.viewports.filter((entry) => entry.id !== selectedId),
        ]
      : scene.viewports;

    const handleHit = hitTestViewportHandle(point, handleViewportCandidates, 6 / viewport.zoom);

    if (handleHit) {
      editorDispatch({ type: 'SELECT_OBJECT', id: handleHit.viewportId, objectType: 'sheetViewport' });
      const selectedViewport = scene.viewports.find((entry) => entry.id === handleHit.viewportId);
      dragState.current = {
        mode: 'resize',
        viewportId: handleHit.viewportId,
        handle: handleHit.handle,
        origin: point,
        initialViewport: selectedViewport || sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
      };
      capturePointer(event.pointerId);
      event.preventDefault();
      return;
    }

    const viewportHit = hitTestViewport(point, scene.viewports);
    if (viewportHit) {
      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
      dragState.current = {
        mode: 'move',
        viewportId: viewportHit.id,
        origin: point,
        initialViewport: viewportHit,
      };
      capturePointer(event.pointerId);
      event.preventDefault();
      return;
    }

    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
    dragState.current = null;
  }, [activePointerId, capturePointer, editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);

  const handlePointerMove = useCallback((event) => {
    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;

    if (isPanning.current) {
      const dx = event.clientX - lastPanPos.current.x;
      const dy = event.clientY - lastPanPos.current.y;
      editorDispatch({ type: 'PAN', dx, dy });
      lastPanPos.current = { x: event.clientX, y: event.clientY };
      return;
    }

    if (!dragState.current || !sheet) return;

    const point = getSheetPos(event);
    const { mode } = dragState.current;

    if (mode === 'rotate') {
      const { center, initialRotation, startAngle, viewportId } = dragState.current;
      const currentAngle = Math.atan2(point.y - center.y, point.x - center.x) * (180 / Math.PI);
      let newRotation = initialRotation + (currentAngle - startAngle);
      if (event.shiftKey) {
        newRotation = Math.round(newRotation / 15) * 15;
      }
      newRotation = ((newRotation % 360) + 360) % 360;
      updateViewport(viewportId, { rotation: newRotation });
      return;
    }

    const { initialViewport, origin, handle, viewportId } = dragState.current;
    const dx = point.x - origin.x;
    const dy = point.y - origin.y;

    if (mode === 'move') {
      updateViewport(viewportId, {
        x: initialViewport.x + dx,
        y: initialViewport.y + dy,
      });
      return;
    }

    const next = {
      x: initialViewport.x,
      y: initialViewport.y,
      width: initialViewport.width,
      height: initialViewport.height,
    };

    if (handle.includes('n')) {
      next.y = initialViewport.y + dy;
      next.height = initialViewport.height - dy;
    }
    if (handle.includes('s')) {
      next.height = initialViewport.height + dy;
    }
    if (handle.includes('w')) {
      next.x = initialViewport.x + dx;
      next.width = initialViewport.width - dx;
    }
    if (handle.includes('e')) {
      next.width = initialViewport.width + dx;
    }

    updateViewport(viewportId, next);
  }, [editorDispatch, getSheetPos, sheet, updateViewport]);

  const handlePointerUp = useCallback((event) => {
    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
    isPanning.current = false;
    dragState.current = null;
    releasePointer(event.pointerId);
  }, [releasePointer]);

  const handlePointerCancel = useCallback((event) => {
    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
    isPanning.current = false;
    dragState.current = null;
    releasePointer(event.pointerId);
  }, [releasePointer]);

  const handleWheel = useCallback((event) => {
    event.preventDefault();
    const rect = svgRef.current.getBoundingClientRect();
    const mouseX = event.clientX - rect.left;
    const mouseY = event.clientY - rect.top;
    const direction = event.deltaY < 0 ? 1 : -1;
    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
  }, [editorDispatch, viewport]);

  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return undefined;
    const prevent = (event) => event.preventDefault();
    svg.addEventListener('contextmenu', prevent);
    svg.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      svg.removeEventListener('contextmenu', prevent);
      svg.removeEventListener('wheel', handleWheel);
    };
  }, [handleWheel]);

  return (
    <div className={styles.canvasContainer}>
      <svg
        ref={svgRef}
        className={styles.svg}
        style={{ cursor: dragState.current ? 'grabbing' : 'default', touchAction: 'none' }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerCancel}
      >
        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
          {sheet ? (
            <SheetRenderer
              project={project}
              sheet={sheet}
              selectedId={selectedId}
              selectedType={selectedType}
            />
          ) : (
            <g className="sheet-empty">
              <rect x={0} y={0} width={420} height={297} fill="#f6f7f9" stroke="#d0d6de" strokeDasharray="2 2" />
              <text x={210} y={148} textAnchor="middle" dominantBaseline="middle" fill="#66768a" fontSize={12}>
                Create a sheet from the sidebar or properties panel.
              </text>
            </g>
          )}
        </g>
      </svg>
      {sheet && scene && (
        <svg
          data-sheet-export-root="true"
          width={scene.paper.width}
          height={scene.paper.height}
          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
          style={{
            position: 'absolute',
            width: 0,
            height: 0,
            overflow: 'hidden',
            pointerEvents: 'none',
            opacity: 0,
          }}
          aria-hidden="true"
        >
          <SheetRenderer
            project={project}
            sheet={sheet}
            selectedId={null}
            selectedType={null}
          />
        </svg>
      )}
      <div className={styles.statusBar}>
        <span>Workspace: sheet</span>
        <span>Sheet: {sheet?.title || 'None'}</span>
        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
      </div>
    </div>
  );
}

import { buildSheetScene } from '@/sheets/layout';
import { SHEET_COLORS, SHEET_TOKENS } from '@/sheets/standards';
import { getViewportHandleRects, getViewportRotationHandle } from '@/sheets/hitTest';
import SheetViewportContent from './SheetViewportContent';
import SheetTitleBlock from './sheet/SheetTitleBlock';

const HANDLE_SIZE = 4;

function EmptyViewportMessage({ viewport, message }) {
  return (
    <text
      x={viewport.x + viewport.width / 2}
      y={viewport.y + viewport.height / 2}
      textAnchor="middle"
      dominantBaseline="middle"
      fill={SHEET_COLORS.textFaint}
      fontSize={4}
      pointerEvents="none"
    >
      {message}
    </text>
  );
}

function ViewportCaption({ viewport }) {
  const isAbove = viewport.caption.position === 'above';
  const ruleY = isAbove ? viewport.y - 2.2 : viewport.y + viewport.height + 1.2;
  const secondaryY = isAbove ? viewport.y - 2.8 : viewport.caption.y;
  const primaryY = secondaryY - 3.1;

  return (
    <g className="sheet-viewport-caption" pointerEvents="none">
      <line
        x1={viewport.x}
        y1={ruleY}
        x2={viewport.x + viewport.width}
        y2={ruleY}
        stroke={SHEET_COLORS.border}
        strokeWidth={0.3}
      />
      <text
        x={viewport.x}
        y={primaryY}
        fontSize={3}
        fill={SHEET_COLORS.text}
        fontWeight={600}
        letterSpacing={0.12}
      >
        {viewport.caption.primaryText}
      </text>
      <text
        x={viewport.x}
        y={secondaryY}
        fontSize={1.9}
        fill={SHEET_COLORS.textMuted}
        letterSpacing={0.12}
      >
        {viewport.caption.secondaryText}
      </text>
    </g>
  );
}

export default function SheetRenderer({ project, sheet, selectedId, selectedType }) {
  const scene = buildSheetScene(project, sheet);
  if (!scene) return null;

  return (
    <g className="sheet">
      <rect
        x={0}
        y={0}
        width={scene.paper.width}
        height={scene.paper.height}
        fill={SHEET_COLORS.sheetBackdrop}
        stroke="none"
      />
      <rect
        x={scene.border.x}
        y={scene.border.y}
        width={scene.border.width}
        height={scene.border.height}
        fill={SHEET_COLORS.paper}
        stroke={selectedType === 'sheet' && selectedId === sheet.id ? '#0f8f74' : SHEET_COLORS.border}
        strokeWidth={selectedType === 'sheet' && selectedId === sheet.id ? 1 : 0.6}
      />
      <rect
        x={scene.liveArea.x}
        y={scene.liveArea.y}
        width={scene.liveArea.width}
        height={scene.liveArea.height}
        fill="none"
        stroke={SHEET_COLORS.divider}
        strokeWidth={0.2}
      />
      <SheetTitleBlock titleBlock={scene.titleBlock} />

      {scene.viewports.map((viewport) => {
        const isSelected = selectedType === 'sheetViewport' && selectedId === viewport.id;
        return (
          <g
            key={viewport.id}
            className="sheet-viewport"
            transform={viewport.rotation ? `rotate(${viewport.rotation}, ${viewport.x + viewport.width / 2}, ${viewport.y + viewport.height / 2})` : undefined}
          >
            <ViewportCaption viewport={viewport} />
            <rect
              x={viewport.x}
              y={viewport.y}
              width={viewport.width}
              height={viewport.height}
              fill={viewport.source.kind === '3d_preview' ? '#f8fafc' : SHEET_COLORS.paper}
              stroke={isSelected ? '#0f8f74' : SHEET_COLORS.border}
              strokeWidth={isSelected ? 0.8 : 0.45}
            />
            <rect
              x={viewport.contentRect.x}
              y={viewport.contentRect.y}
              width={viewport.contentRect.width}
              height={viewport.contentRect.height}
              fill="none"
              stroke={SHEET_COLORS.divider}
              strokeWidth={0.18}
              pointerEvents="none"
            />
            {viewport.source.kind === 'empty' ? (
              <EmptyViewportMessage viewport={viewport} message={viewport.source.message} />
            ) : (
              <svg
                x={viewport.clipRect.x}
                y={viewport.clipRect.y}
                width={viewport.clipRect.width}
                height={viewport.clipRect.height}
                viewBox={`0 0 ${viewport.clipRect.width} ${viewport.clipRect.height}`}
                overflow="hidden"
                pointerEvents="none"
              >
                <g
                  transform={`translate(${viewport.contentTransform.translateX}, ${viewport.contentTransform.translateY}) scale(${viewport.contentTransform.scale})`}
                  pointerEvents="none"
                >
                  <SheetViewportContent source={viewport.source} />
                </g>
              </svg>
            )}
            {isSelected && Object.values(getViewportHandleRects(viewport, HANDLE_SIZE)).map((handleRect) => (
              <rect
                key={`${viewport.id}-${handleRect.x}-${handleRect.y}`}
                x={handleRect.x}
                y={handleRect.y}
                width={handleRect.width}
                height={handleRect.height}
                fill="#ffffff"
                stroke="#0f8f74"
                strokeWidth={0.5}
              />
            ))}
            {isSelected && (() => {
              const rh = getViewportRotationHandle(viewport, HANDLE_SIZE);
              return (
                <>
                  <line
                    x1={rh.stemX}
                    y1={rh.stemY1}
                    x2={rh.stemX}
                    y2={rh.stemY2}
                    stroke="#0f8f74"
                    strokeWidth={0.4}
                  />
                  <circle
                    cx={rh.cx}
                    cy={rh.cy}
                    r={rh.radius}
                    fill="#ffffff"
                    stroke="#0f8f74"
                    strokeWidth={0.5}
                    style={{ cursor: 'grab' }}
                  />
                </>
              );
            })()}
          </g>
        );
      })}
    </g>
  );
}

