121→export function resolveViewportScaleLabel(viewport, source, sheet) {
122→  if (source?.kind === '3d_preview') return 'NTS';
123→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
124→  return `1:${Math.max(1, Math.round(Number(viewport?.scale) || 100))}`;
125→}
126→
127→export function resolveViewportReferenceNote(viewport, source) {
128→  const custom = viewport?.referenceNote?.trim();
129→  if (custom) return custom;
130→  if (source?.kind === '3d_preview') return 'AXONOMETRIC VIEW';
131→  if (source?.kind === 'section') return 'BUILDING SECTION';
132→  if (source?.kind === 'elevation') return 'EXTERIOR ELEVATION';
133→  return 'CONSTRUCTION VIEW';
134→}
135→
136→export function resolveSheetScaleLabel(sheet, viewports = []) {
137→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
138→  if (sheet?.scaleMode === 'per_viewport') return 'As noted';
139→
140→  const explicit = sheet?.scaleLabel?.trim();
141→  if (explicit) return explicit;
142→
143→  const scales = [...new Set(viewports
144→    .filter((viewport) => viewport.source?.kind !== '3d_preview')
145→    .map((viewport) => Math.max(1, Math.round(Number(viewport.scale) || 100))) )];
146→
147→  if (scales.length === 1) return `1:${scales[0]}`;
148→  return 'As noted';
149→}
