151→export function resolveSheetMetadata(project, sheet, index = 0, viewports = []) {
152→  return {
153→    projectTitle: sheet?.titleBlock?.projectTitleOverride?.trim()
154→      || sheet?.projectNameOverride?.trim()
155→      || project?.name?.trim()
156→      || 'Untitled Project',
157→    projectAddress: sheet?.titleBlock?.projectAddressOverride?.trim()
158→      || project?.address?.trim()
159→      || '',
160→    drawingTitle: sheet?.drawingName?.trim()
161→      || getSheetDisplayLabel(sheet, index),
162→    sheetNumber: getSheetNumberLabel(sheet, index),
163→    issueDate: formatSheetDate(sheet?.issueDate || new Date().toISOString()),
164→    scaleLabel: resolveSheetScaleLabel(sheet, viewports),
165→    drawnBy: sheet?.titleBlock?.drawnBy?.trim()
166→      || project?.documentDefaults?.drawnBy?.trim()
167→      || '',
168→    checkedBy: sheet?.titleBlock?.checkedBy?.trim()
169→      || project?.documentDefaults?.checkedBy?.trim()
170→      || '',
171→  };
172→}
