function RevisionBlock({ revisions }) {
  const columnX = revisions.x + 10;
  const rowHeight = (revisions.height - revisions.headerHeight) / 4;
  const rows = [...revisions.rows];
  while (rows.length < 4) {
    rows.push({ id: `blank-${rows.length}`, code: '', date: '', description: '' });
  }

  return (
    <g>
      <rect
        x={revisions.x}
        y={revisions.y}
        width={revisions.width}
        height={revisions.height}
        fill="none"
        stroke={SHEET_COLORS.border}
        strokeWidth={0.35}
      />
      <rect
        x={revisions.x}
        y={revisions.y}
        width={revisions.width}
        height={revisions.headerHeight}
        fill={SHEET_COLORS.panelFill}
        stroke={SHEET_COLORS.border}
        strokeWidth={0.3}
      />
      <line
        x1={columnX}
        y1={revisions.y}
        x2={columnX}
        y2={revisions.y + revisions.height}
        stroke={SHEET_COLORS.border}
        strokeWidth={0.25}
      />
      <line
        x1={columnX + 15}
        y1={revisions.y}
        x2={columnX + 15}
        y2={revisions.y + revisions.height}
        stroke={SHEET_COLORS.border}
        strokeWidth={0.25}
      />
      <text
        x={revisions.x + 1.6}
        y={revisions.y + revisions.headerHeight * 0.62}
        fontSize={1.8}
        fill={SHEET_COLORS.textMuted}
        letterSpacing={0.2}
      >
        REV
      </text>
      <text
        x={columnX + 1.5}
        y={revisions.y + revisions.headerHeight * 0.62}
        fontSize={1.8}
        fill={SHEET_COLORS.textMuted}
        letterSpacing={0.2}
      >
        DATE
      </text>
      <text
        x={columnX + 16.5}
        y={revisions.y + revisions.headerHeight * 0.62}
        fontSize={1.8}
        fill={SHEET_COLORS.textMuted}
        letterSpacing={0.2}
      >
        DESCRIPTION
      </text>
      {rows.map((revision, index) => {
        const y = revisions.y + revisions.headerHeight + rowHeight * index;
        return (
          <g key={revision.id}>
            <line
              x1={revisions.x}
              y1={y}
              x2={revisions.x + revisions.width}
              y2={y}
              stroke={SHEET_COLORS.border}
              strokeWidth={0.22}
            />
            <text x={revisions.x + 1.8} y={y + rowHeight * 0.62} fontSize={2.1} fill={SHEET_COLORS.text}>
              {revision.code}
            </text>
            <text x={columnX + 1.6} y={y + rowHeight * 0.62} fontSize={1.9} fill={SHEET_COLORS.textMuted}>
              {revision.date}
            </text>
            <text x={columnX + 16.5} y={y + rowHeight * 0.62} fontSize={1.9} fill={SHEET_COLORS.text}>
              {revision.description}
            </text>
          </g>
        );
      })}
    </g>
  );
}

export default function SheetTitleBlock({ titleBlock }) {

    contentTransform: buildContentTransform(viewport, source, contentRect),
    autoLayoutApplied: !viewport.lockAutoLayout,
  };
}

function buildTitleBlock(project, sheet, titleBlockRect, index, viewports) {
  const meta = resolveSheetMetadata(project, sheet, index, viewports);
  const revisionWidth = Math.max(44, titleBlockRect.width * 0.28);
  const infoX = titleBlockRect.x + titleBlockRect.width - revisionWidth;
  const mainWidth = titleBlockRect.width - revisionWidth;
  const bandHeight = titleBlockRect.height * 0.3;
  const titleHeight = titleBlockRect.height * 0.36;
  const metaRowHeight = (titleBlockRect.height - bandHeight - titleHeight) / 2;
  const metaLabelWidth = 15;
  const visibleRevisions = [...(sheet?.revisions || [])].slice(-4).reverse();

  return {
    frame: titleBlockRect,
    projectBand: {
      x: titleBlockRect.x,
      y: titleBlockRect.y,
      width: mainWidth,
      height: bandHeight,
      title: meta.projectTitle,
      address: meta.projectAddress,
    },
    drawingCell: {
      x: titleBlockRect.x,
      y: titleBlockRect.y + bandHeight,
      width: mainWidth * 0.68,
      height: titleHeight,
      label: 'DRAWING TITLE',
      value: meta.drawingTitle,
    },
    numberCell: {
      x: titleBlockRect.x + mainWidth * 0.68,
      y: titleBlockRect.y + bandHeight,
      width: mainWidth * 0.32,
      height: titleHeight,
      label: 'SHEET NO.',
      value: meta.sheetNumber,
    },
    metaRows: [
      {
        x: titleBlockRect.x,
        y: titleBlockRect.y + bandHeight + titleHeight,
        width: mainWidth / 2,
        height: metaRowHeight,
        labelWidth: metaLabelWidth,
        label: 'DATE',
        value: meta.issueDate,
      },
      {
        x: titleBlockRect.x + mainWidth / 2,
        y: titleBlockRect.y + bandHeight + titleHeight,
        width: mainWidth / 2,
        height: metaRowHeight,
        labelWidth: metaLabelWidth,
        label: 'SCALE',
        value: meta.scaleLabel,
      },
      {
        x: titleBlockRect.x,
        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
        width: mainWidth / 2,
        height: metaRowHeight,
        labelWidth: metaLabelWidth,
        label: 'DRAWN BY',
        value: meta.drawnBy || 'TBD',
      },
      {
        x: titleBlockRect.x + mainWidth / 2,
        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
        width: mainWidth / 2,
        height: metaRowHeight,
        labelWidth: metaLabelWidth,
        label: 'CHECKED',
        value: meta.checkedBy || 'TBD',
      },
    ],
    revisions: {
      x: infoX,
      y: titleBlockRect.y,
      width: revisionWidth,
      height: titleBlockRect.height,
      headerHeight: 8,
      rows: visibleRevisions,
    },
  };
}
